import { motion } from "framer-motion";
import { handleLink } from "../../libs/functions";

import {
  Link,
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerBody,
  Listbox,
  ListboxItem,
  Divider,
} from "@nextui-org/react";

import Redes from "../../components/Redes";
import Logo from "../../components/Logo";

import { FaArrowLeft } from "react-icons/fa";

function MenuMovilDrawer({ menuItems, isOpen, onOpenChange }) {
  const text_class = "text-custom2 dark:text-custom1 navidad:text-custom1-5";

  return (
    <Drawer
      isOpen={isOpen}
      onOpenChange={onOpenChange}
      placement="left"
      size="xs"
      className="xs:max-w-[250px]"
      classNames={{
        closeButton: "test text-2xl top-5 end-3",
      }}
      motionProps={{
        variants: {
          enter: {
            opacity: 1,
            x: 0,
            duration: 0.3,
          },
          exit: {
            x: -100,
            opacity: 0,
            duration: 0.3,
          },
        },
      }}
    >
      <DrawerContent>
        {() => (
          <>
            <DrawerHeader>
              <Link
                className="hover:scale-110 transition-all"
                href="#inicio"
                onPress={onOpenChange}
                aria-label="Ir al inicio de la pagina"
              >
                <Logo
                  id="menu_movil_logo"
                  classNames={{
                    svgA: "h-full w-auto max-h-[44px]",
                  }}
                />
              </Link>
            </DrawerHeader>

            <Divider className="w-4/5 self-center" />

            <DrawerBody className="h-fit px-2">
              <motion.div
                variants={{
                  hidden: {},
                  visible: {
                    transition: {
                      delayChildren: 0.1,
                      staggerChildren: 0.1,
                    },
                  },
                }}
                initial="hidden"
                whileInView="visible"
              >
                <Listbox
                  aria-label="Lista de secciones"
                  variant="faded"
                  onAction={(id) => {
                    handleLink(id);
                    onOpenChange();
                  }}
                  classNames={{}}
                >
                  {menuItems.map((item) => (
                    <ListboxItem
                      key={item}
                      textValue={item}
                      className={`${text_class} capitalize py-2 transition-all hover:shadow-md`}
                      classNames={{ title: "text-lg font-semibold" }}
                      href={`#${item}`}
                    >
                      <motion.p
                        variants={{
                          hidden: {
                            opacity: 0,
                            scale: 1.5,
                          },
                          visible: {
                            opacity: 1,
                            scale: 1,
                          },
                        }}
                      >
                        {item}
                      </motion.p>
                    </ListboxItem>
                  ))}

                  <ListboxItem
                    key="Cerrar"
                    textValue="Cerrar"
                    className="dark:text-white py-2 transition-all hover:shadow-md"
                    classNames={{
                      title: "text-lg font-semibold flex gap-2 items-center",
                    }}
                  >
                    <FaArrowLeft />
                    Cerrar
                  </ListboxItem>
                </Listbox>
              </motion.div>

              <Divider className="w-4/5 self-center" />

              <Redes
                className="flex-wrap px-2"
                classNames={{
                  link: "p-3 shadow-none text-3xl text-foreground",
                }}
                variants={{
                  hidden: {
                    opacity: 0,
                  },
                  visible: {
                    opacity: 1,
                  },
                }}
              />
            </DrawerBody>
          </>
        )}
      </DrawerContent>
    </Drawer>
  );
}

export default MenuMovilDrawer;
